	@Test
	void basicServletConfigCopiesAndOverridesParameters() {
		MockServletContext servletContext = new MockServletContext();
		TestServletConfig parent = new TestServletConfig("parent", servletContext,
				java.util.Map.of("a", "1", "b", "2"));

		BasicServletConfig copy = new BasicServletConfig("child", parent, java.util.Map.of("b", "override", "c", "3"));

		assertThat(copy.getServletName()).isEqualTo("child");
		assertThat(copy.getServletContext()).isSameAs(servletContext);
		assertThat(copy.getInitParameter("a")).isEqualTo("1");
		assertThat(copy.getInitParameter("b")).isEqualTo("override");
		assertThat(copy.getInitParameter("c")).isEqualTo("3");
		assertThat(Collections.list(copy.getInitParameterNames())).containsExactlyInAnyOrder("a", "b", "c");
	}

	@Test
	void dynamicHttpRequestAllowsOverridingMutableFields() {
		HttpServletRequest request = mock(HttpServletRequest.class);
		when(request.getContextPath()).thenReturn("/rdf4j-workbench");
		when(request.getMethod()).thenReturn("GET");
		when(request.getServletPath()).thenReturn("/repositories");
		when(request.getPathInfo()).thenReturn("/test");
		when(request.getQueryString()).thenReturn("a=1");
		when(request.getLocale()).thenReturn(Locale.ENGLISH);

		DynamicHttpRequest dynamicRequest = new DynamicHttpRequest(request);
		dynamicRequest.setContextPath("/alt");
		dynamicRequest.setMethod("POST");
		dynamicRequest.setServletPath("/changed");
		dynamicRequest.setPathInfo("/value");
		dynamicRequest.setQueryString("b=2");
		dynamicRequest.setLocale(Locale.GERMAN);

		assertThat(dynamicRequest.getContextPath()).isEqualTo("/alt");
		assertThat(dynamicRequest.getMethod()).isEqualTo("POST");
		assertThat(dynamicRequest.getServletPath()).isEqualTo("/changed");
		assertThat(dynamicRequest.getPathInfo()).isEqualTo("/value");
		assertThat(dynamicRequest.getQueryString()).isEqualTo("b=2");
		assertThat(dynamicRequest.getLocale()).isEqualTo(Locale.GERMAN);
	}

	@Test
	void queryStringBuilderReplacesAllOccurrencesAndQuotesValues() {
		QueryStringBuilder builder = new QueryStringBuilder("ASK { $<uri> $<uri> $<quoted> $<typed> }");

		builder.replaceURI("$<uri>", "urn:test");
		builder.replaceQuote("$<quoted>", "hello");
		builder.replace("$<typed>", QueryStringBuilder.xsdQuote("7", "integer"));

		assertThat(builder.toString())
				.isEqualTo("ASK { <urn:test> <urn:test> \"hello\" \"7\"^^xsd:integer }");
	}

	@Test
	void queryStringBuilderRejectsMissingTemplateVariables() {
		assertThatIllegalArgumentException().isThrownBy(() -> new QueryStringBuilder(null));
		assertThatIllegalArgumentException().isThrownBy(() -> new QueryStringBuilder(""));
		assertThatIllegalArgumentException().isThrownBy(() -> new QueryStringBuilder("ASK {}"));
	}

